Step 2: Add custom Javascript

function initCopyEmailClipboard() {
  const buttons = document.querySelectorAll('.copy-email-button');
  if (!buttons.length) return;

  const copyEmail = (button) => {
  	// Email to copy to clipboard is taking from the button itself, or if that's empty,
    // from a text element inside the button
    const email =
      button.getAttribute('data-copy-email') ||
      button.querySelector('[data-copy-email-element]').textContent.trim();
    if (email) {
      navigator.clipboard.writeText(email).then(() => {
        button.setAttribute('data-copy-button', 'copied');
        button.setAttribute('aria-label', 'Email copied to clipboard!');
      });
    }
  };

  const handleInteraction = (e) => {
    if (
      e.type === 'click' ||
      (e.type === 'keydown' && (e.key === 'Enter' || e.key === ' '))
    ) {
      e.preventDefault();
      copyEmail(e.currentTarget);
    }
  };

  buttons.forEach((button) => {
    button.addEventListener('click', handleInteraction);
    button.addEventListener('keydown', handleInteraction);
    button.addEventListener('mouseleave', () => {
    	// Remove 'active' attribute to reset color and text transform
      button.removeAttribute('data-copy-button');
      // Remove focus on mouseleave to clear keyboard focus styling
      button.blur();
      button.setAttribute('aria-label', 'Copy email to clipboard');
    });
    button.addEventListener('blur', () => {
      button.removeAttribute('data-copy-button');
      button.setAttribute('aria-label', 'Copy email to clipboard');
    });
  });
}

// Initialize Copy Email to Clipboard Button
document.addEventListener('DOMContentLoaded', () => {
  initCopyEmailClipboard();
});

Implementation
This JavaScript module provides an accessible way for users to copy an email address to their clipboard. The email is either defined as a data-copy-email attribute on the button or extracted from an inner element marked with data-copy-email-element.‍

‍Event Handling
Listeners are added for both click and keyboard (Enter or Space) interactions to trigger the copy action.‍

Clipboard Interaction
Uses the Clipboard API to copy the email to the user’s clipboard.‍

State & Accessibility
Once copied, the button’s state is updated with a data-copy-button="copied" attribute, and its aria-label is set to notify screen readers (“Email copied to clipboard!”). When the mouse leaves the button or it loses focus, the copied state is reset and the default aria-label (“Copy email to clipboard”) is restored.‍

Graceful Fallback
If no email is directly provided on the button, the script looks for an inner element containing the email text.

